-- Settings/reference fixture tables required by MY_Controller's unconditional
-- model autoload chain (application/core/MY_Controller.php:19-20) to avoid a
-- 500 error on ANY authenticated admin request against school_saas, discovered
-- during Phase 2 Stage 6's live end-to-end verification. See
-- docs/superpowers/plans/2026-07-10-multi-tenant-phase2-stage6-real-staff-retrofit.md
-- ("Post-Task-5 fix" section) for full rationale.
--
-- currencies, languages: global reference catalogs (not tenant-scoped -- these
-- are app-wide lists, e.g. world currencies/languages, not school-owned data).
-- Copied in full from al_hafeez_campus (same content expected across schools).
--
-- sch_settings: genuinely per-school data, tenant-scoped. Real row for tenant 25,
-- copied from al_hafeez_campus with session_id remapped to school_saas's Stage 5
-- migrated id (source id 22 -> target id 11, both '2026-27').
--
-- email_config, permission_group, student_fees_master: structural-only fixture
-- tables. Their autoloaded models' constructors only check the table EXISTS
-- (schema introspection / self-migrating column checks), never fetch real rows
-- for this flow -- so these are created EMPTY, with FK constraints to
-- not-yet-migrated tables (fee_session_groups, etc.) deliberately omitted, since
-- no real data is ever inserted into them by anything in scope for this stage.

USE school_saas;

CREATE TABLE `currencies` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(100) DEFAULT NULL,
  `short_name` varchar(100) DEFAULT NULL,
  `symbol` varchar(10) DEFAULT NULL,
  `base_price` varchar(10) NOT NULL DEFAULT '1',
  `is_active` int(11) DEFAULT 0,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=180 DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci;
